    ('and-also', 0, $$Thabo pretends that his bed is a raft on the sea!$$, $$[{"role": "BODY", "text": "Thabo pretends that his bed is a raft on the sea!", "bbox": [300.5, 72.3, 543.9, 151.3], "size": 25.0}]$$),
    ('and-also', 1, $$His little sister Keitu says, “Yes! And also! There are sharks.” “No!” says Thabo.$$, $$[{"role": "BODY", "text": "His little sister Keitu says, “Yes! And also! There are sharks.”", "bbox": [103.0, 62.7, 463.9, 114.7], "size": 25.0}, {"role": "BODY", "text": "“No!” says Thabo.", "bbox": [732.8, 83.2, 941.3, 109.1], "size": 25.0}]$$),
    ('and-also', 2, $$Thabo pretends that their taxi is a spaceship!$$, $$[{"role": "BODY", "text": "Thabo pretends that their taxi is a spaceship!", "bbox": [124.2, 93.8, 502.9, 146.7], "size": 25.0}]$$),
    ('and-also', 3, $$His little sister Keitu says, “Yes! And also! Watch out for shooting stars !” “No,” says Thabo.$$, $$[{"role": "BODY", "text": "His little sister Keitu says, “Yes! And also! Watch out for shooting stars !”", "bbox": [63.0, 15.8, 536.5, 68.7], "size": 25.0}, {"role": "BODY", "text": "“No,” says Thabo.", "bbox": [756.6, 42.6, 965.4, 68.5], "size": 25.0}]$$),
    ('and-also', 4, $$Thabo pretends the playground is a jungle !$$, $$[{"role": "BODY", "text": "Thabo pretends the playground is a jungle !", "bbox": [596.1, 510.1, 1104.7, 536.0], "size": 25.0}]$$),
    ('and-also', 5, $$“No,” says Thabo. His little sister Keitu says, “Yes! And also! We are lions .”$$, $$[{"role": "BODY", "text": "“No,” says Thabo.", "bbox": [849.7, 66.9, 1058.4, 92.8], "size": 25.0}, {"role": "BODY", "text": "His little sister Keitu says, “Yes! And also! We are lions .”", "bbox": [100.6, 499.9, 460.7, 552.8], "size": 25.0}]$$),
    ('and-also', 6, $$“Oh!” says Thabo, “Wait! Wow! Yes! That’s a great idea!” “I know!” says Keitu.$$, $$[{"role": "BODY", "text": "“Oh!” says Thabo, “Wait! Wow! Yes! That’s a great idea!”", "bbox": [92.2, 70.3, 501.7, 123.2], "size": 25.0}, {"role": "BODY", "text": "“I know!” says Keitu.", "bbox": [732.7, 86.0, 968.1, 111.0], "size": 25.0}]$$),
    ('and-also', 7, $$Thabo pretends to be a lion! Keitu also pretends to be a lion!$$, $$[{"role": "BODY", "text": "Thabo pretends to be a lion!", "bbox": [116.7, 63.4, 450.2, 89.3], "size": 25.0}, {"role": "BODY", "text": "Keitu also pretends to be a lion!", "bbox": [652.0, 63.4, 1025.4, 89.3], "size": 25.0}]$$),
    ('and-also', 8, $$Thabo pretends the other kids are a river of crocodiles! Keitu says, “Yes! And also! We can jump on this log to float away.”$$, $$[{"role": "BODY", "text": "Thabo pretends the other kids are a river of crocodiles!", "bbox": [70.6, 63.4, 496.4, 116.3], "size": 25.0}, {"role": "BODY", "text": "Keitu says, “Yes! And also! We can jump on this log to float away.”", "bbox": [809.5, 37.9, 1113.0, 117.8], "size": 25.0}]$$),
    ('and-also', 9, $$Story spread 10 “Yes! And also!” Thabo says, “We can slide down the rainbow!” Keitu says, “Yes! And also! Watch out for the dinosaurs!”$$, $$[{"role": "BODY", "text": "Story spread 10", "bbox": [-127.6, -112.2, 17.2, -88.2], "size": 24.0}, {"role": "BODY", "text": "“Yes! And also!” Thabo says, “We can slide down the rainbow!”", "bbox": [241.0, 28.7, 530.9, 108.6], "size": 25.0}, {"role": "BODY", "text": "Keitu says, “Yes! And also! Watch out for the dinosaurs!”", "bbox": [622.4, 55.8, 858.7, 135.7], "size": 25.0}]$$),
    ('and-also', 10, $$$$, $$[]$$),
    ('and-also', 11, $$Thabo says,“I had the best day playing pretend with you.” Keitu says, “And also! We should play again tomorrow!”$$, $$[{"role": "BODY", "text": "Thabo says,“I had the best day playing pretend with you.”", "bbox": [265.9, 72.6, 522.1, 151.6], "size": 25.0}, {"role": "BODY", "text": "Keitu says, “And also! We should play again tomorrow!”", "bbox": [656.8, 70.5, 1053.2, 121.3], "size": 25.0}]$$),
    ('and-also', 12, $$$$, $$[]$$),
    ('and-also', 13, $$$$, $$[]$$),
    ('ann-nem-oh-nee-finds-adventure', 0, $$Ann-Nem-Oh-Nee lived in the ocean. All day long she clung to the same slippery rock with her single big foot. Her tiny tentacles caught tasty treats.$$, $$[{"role": "BODY", "text": "Ann-Nem-Oh-Nee lived in the ocean. All day long she clung to the same slippery rock with her single big foot. Her tiny tentacles caught tasty treats.", "bbox": [56.7, 224.9, 497.0, 335.3], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 1, $$On days when she felt cross, her stinging tentacles kept the other creatures away.$$, $$[{"role": "BODY", "text": "On days when she felt cross, her stinging tentacles kept the other creatures away.", "bbox": [680.3, 372.3, 1036.4, 453.9], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 2, $$But today her rock felt lonely.$$, $$[{"role": "BODY", "text": "But today her rock felt lonely.", "bbox": [127.6, 307.8, 452.0, 331.8], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 3, $$“I have no fins. I have no feet. I am different to every other creature.”$$, $$[{"role": "BODY", "text": "“I have no fins.", "bbox": [150.2, 149.0, 309.2, 173.0], "size": 24.0}, {"role": "BODY", "text": "I have no feet.", "bbox": [70.9, 293.6, 226.0, 317.6], "size": 24.0}, {"role": "BODY", "text": "I am different to every other creature.”", "bbox": [643.5, 213.5, 890.2, 266.3], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 4, $$“Even that hermit crab is off having adventures!” “Save me! That fish wants to pluck me out of my shell!”$$, $$[{"role": "BODY", "text": "“Even that hermit crab is off having adventures!”", "bbox": [70.9, 82.4, 459.5, 135.2], "size": 24.0}, {"role": "BODY", "text": "“Save me! That fish wants to pluck me out of my shell!”", "bbox": [637.8, 174.6, 950.0, 227.3], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 5, $$Ann-Nem-Oh-Nee whipped up her stinging tentacles and hid the hermit underneath them. “Go away, you big bully!” The big fish bared his teeth, but was afraid of being stung.$$, $$[{"role": "BODY", "text": "Ann-Nem-Oh-Nee whipped up her stinging tentacles and hid the hermit underneath them.", "bbox": [70.9, 107.2, 473.3, 188.8], "size": 24.0}, {"role": "BODY", "text": "“Go away, you big bully!”", "bbox": [637.8, 405.0, 909.4, 429.0], "size": 24.0}, {"role": "BODY", "text": "The big fish bared his teeth, but was afraid of being stung.", "bbox": [637.8, 462.6, 1034.7, 515.4], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 6, $$He gave up and swam away with a cheeky flick of his tail. “That was close!” said the crab. “Is it safe now?” “You can come out, Crab. What’s your name?” “Herman. I’m a hermit, but I think I need a bodyguard. I wish I was as brave as you!”$$, $$[{"role": "BODY", "text": "He gave up and swam away with a cheeky flick of his tail.", "bbox": [70.9, 61.9, 458.4, 114.7], "size": 24.0}, {"role": "BODY", "text": "“That was close!” said the crab. “Is it safe now?”", "bbox": [70.9, 148.3, 463.0, 201.1], "size": 24.0}, {"role": "BODY", "text": "“You can come out, Crab. What’s your name?”", "bbox": [623.6, 347.4, 1038.8, 400.2], "size": 24.0}, {"role": "BODY", "text": "“Herman. I’m a hermit, but I think I need a bodyguard. I wish I was as brave as you!”", "bbox": [623.6, 433.8, 1058.7, 515.4], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 7, $$“I’m Ann-Nem-Oh-Nee. I wish I had amazing adventures like you.” “But why don’t you?” He asked. “I’m stuck to my rock. And I don’t have legs!” She replied. “Well, I don’t have stings, but I do have an idea!”$$, $$[{"role": "BODY", "text": "“I’m Ann-Nem-Oh-Nee. I wish I had amazing adventures like you.”", "bbox": [56.7, 61.9, 437.6, 114.7], "size": 24.0}, {"role": "BODY", "text": "“But why don’t you?” He asked.", "bbox": [265.0, 151.0, 492.5, 203.8], "size": 24.0}, {"role": "BODY", "text": "“I’m stuck to my rock. And I don’t have legs!” She replied.", "bbox": [623.6, 151.0, 1044.3, 203.8], "size": 24.0}, {"role": "BODY", "text": "“Well, I don’t have stings, but I do have an idea!”", "bbox": [802.2, 246.1, 1072.7, 298.9], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 8, $$Herman took Ann-Nem-Oh-Nee by the tentacle and danced around her, pulling silly faces. First Ann-Nem-Oh-Nee snorted, and then she giggled — and then she laughed so hard she popped right off her rock.$$, $$[{"role": "BODY", "text": "Herman took Ann-Nem-Oh-Nee by the tentacle and danced around her, pulling silly faces.", "bbox": [56.7, 61.9, 497.2, 143.5], "size": 24.0}, {"role": "BODY", "text": "First Ann-Nem-Oh-Nee snorted, and then she giggled — and then she laughed so hard she popped right off her rock.", "bbox": [623.6, 61.9, 1077.2, 143.5], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 9, $$Herman gently picked her up and settled her on his shell. “Are you ready? I feel an adventure coming on.” He said.$$, $$[{"role": "BODY", "text": "Herman gently picked her up and settled her on his shell.", "bbox": [623.6, 219.1, 1074.6, 271.9], "size": 24.0}, {"role": "BODY", "text": "“Are you ready? I feel an adventure coming on.” He said.", "bbox": [623.6, 305.4, 1014.2, 358.2], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 10, $$Ann-Nem-Oh-Nee adventures all over the ocean, catching tasty treats. Now she only uses her stinging tentacles to keep the nasty fish away from Herman.$$, $$[{"role": "BODY", "text": "Ann-Nem-Oh-Nee adventures all over the ocean, catching tasty treats.", "bbox": [56.7, 249.0, 475.2, 301.8], "size": 24.0}, {"role": "BODY", "text": "Now she only uses her stinging tentacles to keep the nasty fish away from Herman.", "bbox": [623.6, 249.0, 1088.2, 301.8], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 11, $$And she never, ever feels lonely.$$, $$[{"role": "BODY", "text": "And she never, ever feels lonely.", "bbox": [674.4, 276.6, 1026.4, 300.6], "size": 24.0}]$$),
    ('ann-nem-oh-nee-finds-adventure', 12, $$$$, $$[]$$),
    ('ann-nem-oh-nee-finds-adventure', 13, $$Photo credit: Prof. C.L. Griffiths$$, $$[{"role": "BODY", "text": "Photo credit: Prof. C.L. Griffiths", "bbox": [344.9, 443.4, 510.2, 455.4], "size": 12.0}]$$),
    ('auntie-bois-gift', 0, $$Kopano and Rea are going to town for the first time ever!$$, $$[{"role": "BODY", "text": "Kopano and Rea are going to town for the first time ever!", "bbox": [623.6, 89.7, 1050.7, 141.7], "size": 24.0}]$$),
    ('auntie-bois-gift', 1, $$“Remember to fasten your seatbelts,” Mama says. “Auntie Boi has sent you girls a gift and we’re going to collect it at the big post office in town.” “We can’t wait to see the gift Mama,” the girls say and off they go.$$, $$[{"role": "BODY", "text": "“Remember to fasten your seatbelts,” Mama says.", "bbox": [625.0, 263.1, 1038.9, 315.1], "size": 24.0}, {"role": "BODY", "text": "“Auntie Boi has sent you girls a gift and we’re going to collect it at the big post office in town.”", "bbox": [625.0, 347.1, 1057.6, 427.1], "size": 24.0}, {"role": "BODY", "text": "“We can’t wait to see the gift Mama,” the girls say and off they go.", "bbox": [625.0, 459.1, 1072.1, 511.1], "size": 24.0}]$$),
    ('auntie-bois-gift', 2, $$“The Nelson Mandela Bridge leads us into town,” Mama says. “Mhhmm, Nelson Mandela Bridge,” Kopano says.$$, $$[{"role": "BODY", "text": "“The Nelson Mandela Bridge leads us into town,” Mama says.", "bbox": [623.6, 111.0, 1033.9, 163.0], "size": 24.0}, {"role": "BODY", "text": "“Mhhmm, Nelson Mandela Bridge,” Kopano says.", "bbox": [623.6, 195.0, 1004.1, 247.0], "size": 24.0}]$$),
    ('auntie-bois-gift', 3, $$“Look,” Rea says to Kopano, “so many tall buildings.” “Mhhmm, do you think our gift is tall too Rea?” Kopano asks.$$, $$[{"role": "BODY", "text": "“Look,” Rea says to Kopano, “so many tall buildings.”", "bbox": [638.5, 76.8, 1059.1, 128.8], "size": 24.0}, {"role": "BODY", "text": "“Mhhmm, do you think our gift is tall too Rea?” Kopano asks.", "bbox": [638.5, 160.8, 1079.1, 212.8], "size": 24.0}]$$),
    ('auntie-bois-gift', 4, $$“Look,” Kopano says to Rea, “so many fruits and vegetables.” “Mhhmm, do you think our gift tastes yummy?” Rea asks Kopano. FRUITS AND VEGETABLES$$, $$[{"role": "BODY", "text": "“Look,” Kopano says to Rea, “so many fruits and vegetables.”", "bbox": [54.6, 94.5, 475.2, 146.5], "size": 24.0}, {"role": "BODY", "text": "“Mhhmm, do you think our gift tastes yummy?” Rea asks Kopano.", "bbox": [54.6, 178.5, 461.9, 230.5], "size": 24.0}, {"role": "BODY", "text": "FRUITS AND VEGETABLES", "bbox": [761.5, 443.4, 939.2, 506.3], "size": 29.0}]$$),
    ('auntie-bois-gift', 5, $$“Look,” Rea says to Kopano, “traditional clothes!” “Mhhmm, do you think Auntie Boi bought us traditional clothes?” Kopano asks.$$, $$[{"role": "BODY", "text": "“Look,” Rea says to Kopano, “traditional clothes!”", "bbox": [58.1, 95.7, 495.4, 147.7], "size": 24.0}, {"role": "BODY", "text": "“Mhhmm, do you think Auntie Boi bought us traditional clothes?” Kopano asks.", "bbox": [58.1, 179.7, 508.4, 231.7], "size": 24.0}, {"role": "DECOR", "text": "OPEN", "bbox": [724.6, 137.6, 774.5, 160.7], "size": 19.4}]$$),
    ('auntie-bois-gift', 6, $$“Wow, it’s like one big party,” Kopano and Rea say. “Maybe your gift sings a loud song,” Mama says smiling. “Mhhmm, we love loud songs,” the girls say.$$, $$[{"role": "DECOR", "text": "OPEN", "bbox": [422.4, 236.2, 472.3, 259.2], "size": 19.4}, {"role": "BODY", "text": "“Wow, it’s like one big party,” Kopano and Rea say.", "bbox": [652.0, 62.5, 1060.9, 114.5], "size": 24.0}, {"role": "BODY", "text": "“Maybe your gift sings a loud song,” Mama says smiling.", "bbox": [652.0, 146.5, 1048.0, 198.5], "size": 24.0}, {"role": "BODY", "text": "“Mhhmm, we love loud songs,” the girls say.", "bbox": [652.0, 230.5, 1026.5, 282.5], "size": 24.0}]$$),
    ('auntie-bois-gift', 7, $$“We are here!” Mama says. POST OFFICE$$, $$[{"role": "BODY", "text": "“We are here!” Mama says.", "bbox": [114.1, 120.0, 408.4, 144.0], "size": 24.0}, {"role": "BODY", "text": "POST OFFICE", "bbox": [822.5, 133.1, 1089.0, 176.0], "size": 42.8}, {"role": "DECOR", "text": "OPEN", "bbox": [947.0, 288.8, 977.9, 303.0], "size": 12.0}]$$),
    ('auntie-bois-gift', 8, $$SHAKE! SHAKE! RATTLE! SHAKE! “Do you think it’s tall like the buildings we saw?” Rea asks. “No,” Kopano says. Rea takes the box and smells it. “Do you think it tastes yummy like the fruit and veg we saw?” “No,” Rea says. Kopano shakes the box again. “It doesn’t make a loud noise like the speakers we passed.” “And either,” I don’t Rea says. think it’s traditional clothes$$, $$[{"role": "BODY", "text": "SHAKE!", "bbox": [298.0, 101.1, 364.8, 125.7], "size": 20.1}, {"role": "BODY", "text": "SHAKE!", "bbox": [466.3, 144.8, 534.4, 179.0], "size": 21.7}, {"role": "BODY", "text": "RATTLE!", "bbox": [468.1, 448.6, 545.2, 479.1], "size": 20.8}, {"role": "BODY", "text": "SHAKE!", "bbox": [355.1, 464.5, 423.2, 501.8], "size": 22.1}, {"role": "BODY", "text": "“Do you think it’s tall like the buildings we saw?” Rea asks.", "bbox": [635.0, 38.6, 1048.1, 90.7], "size": 24.0}, {"role": "BODY", "text": "“No,” Kopano says. Rea takes the box and smells it.", "bbox": [635.0, 122.7, 1047.6, 174.7], "size": 24.0}, {"role": "BODY", "text": "“Do you think it tastes yummy like the fruit and veg we saw?”", "bbox": [635.0, 206.7, 1051.7, 258.6], "size": 24.0}, {"role": "BODY", "text": "“No,” Rea says.", "bbox": [635.0, 290.6, 799.7, 314.6], "size": 24.0}, {"role": "BODY", "text": "Kopano shakes the box again. “It doesn’t make a loud noise like the speakers we passed.”", "bbox": [635.0, 346.6, 1082.2, 426.6], "size": 24.0}, {"role": "BODY", "text": "“And either,” I don’t Rea says. think it’s traditional clothes", "bbox": [635.0, 458.6, 1061.5, 510.6], "size": 24.0}]$$),
    ('auntie-bois-gift', 9, $$Kopano and Rea sit down right there on the floor of the post office and open the box.$$, $$[{"role": "BODY", "text": "Kopano and Rea sit down right there on the floor of the post office and open the box.", "bbox": [121.9, 211.5, 380.2, 319.5], "size": 24.0}]$$),
    ('auntie-bois-gift', 10, $$“Those are Maasai dolls,” Mama says to the girls. “Maasai dolls from Kenya,” Kopano says. “We love these dolls!” Rea says.$$, $$[{"role": "BODY", "text": "“Those are Maasai dolls,” Mama says to the girls.", "bbox": [56.7, 330.8, 495.1, 382.8], "size": 24.0}, {"role": "BODY", "text": "“Maasai dolls from Kenya,” Kopano says.", "bbox": [56.7, 414.8, 508.7, 438.8], "size": 24.0}, {"role": "BODY", "text": "“We love these dolls!” Rea says.", "bbox": [56.7, 470.8, 401.4, 494.8], "size": 24.0}]$$),
    ('auntie-bois-gift', 11, $$Mama takes a picture of the girls and sends it to Auntie Boi.$$, $$[{"role": "BODY", "text": "Mama takes a picture of the girls and sends it to Auntie Boi.", "bbox": [623.6, 462.4, 1036.5, 514.4], "size": 24.0}]$$),
