    ('baby-babble', 0, $$Which shoes ? You choose!$$, $$[{"role": "BODY", "text": "Which shoes ? You choose!", "bbox": [633.6, 273.2, 1067.2, 312.4], "size": 36.0}]$$),
    ('baby-babble', 1, $$Please, please! More peas !$$, $$[{"role": "BODY", "text": "Please, please! More peas !", "bbox": [163.5, 251.6, 403.4, 334.0], "size": 36.0}]$$),
    ('baby-babble', 2, $$Num-num? Yum-yum!$$, $$[{"role": "BODY", "text": "Num-num? Yum-yum!", "bbox": [665.7, 273.2, 1035.1, 312.4], "size": 36.0}]$$),
    ('baby-babble', 3, $$All gone! Full tum.$$, $$[{"role": "BODY", "text": "All gone! Full tum.", "bbox": [134.3, 273.2, 432.6, 312.4], "size": 36.0}]$$),
    ('baby-babble', 4, $$Sore, sore . . . Teeth are sore.$$, $$[{"role": "BODY", "text": "Sore, sore . . . Teeth are sore.", "bbox": [726.3, 251.6, 974.5, 334.0], "size": 36.0}]$$),
    ('baby-babble', 5, $$Nice, nice! Ice is nice.$$, $$[{"role": "BODY", "text": "Nice, nice! Ice is nice.", "bbox": [113.5, 273.2, 453.4, 312.4], "size": 36.0}]$$),
    ('baby-babble', 6, $$Who’s there?$$, $$[{"role": "BODY", "text": "Who’s there?", "bbox": [741.5, 268.3, 959.2, 307.4], "size": 36.0}]$$),
    ('baby-babble', 7, $$Teddy bear!$$, $$[{"role": "BODY", "text": "Teddy bear!", "bbox": [180.3, 276.4, 386.6, 312.4], "size": 36.0}]$$),
    ('baby-babble', 8, $$Where’s dum-dum? Baby sad .$$, $$[{"role": "BODY", "text": "Where’s dum-dum? Baby sad .", "bbox": [121.1, 250.9, 445.8, 333.2], "size": 36.0}]$$),
    ('baby-babble', 9, $$There’s dum-dum! Baby glad .$$, $$[{"role": "BODY", "text": "There’s dum-dum! Baby glad .", "bbox": [700.0, 251.6, 1000.8, 334.0], "size": 36.0}]$$),
    ('baby-babble', 10, $$Splish, splosh! Time to wash .$$, $$[{"role": "BODY", "text": "Splish, splosh! Time to wash .", "bbox": [168.2, 251.6, 398.8, 334.0], "size": 36.0}]$$),
    ('baby-babble', 11, $$Night night, sleep tight!$$, $$[{"role": "BODY", "text": "Night night, sleep tight!", "bbox": [75.8, 273.2, 457.1, 312.4], "size": 36.0}]$$),
    ('baby-babble', 12, $$$$, $$[]$$),
    ('baby-babble', 13, $$$$, $$[]$$),
    ('baby-talk', 0, $$Tayo can’t wait to meet his baby sister. Hurry up Mama! Let her out of your tummy.$$, $$[{"role": "BODY", "text": "Tayo can’t wait to meet his baby sister. Hurry up Mama! Let her out of your tummy.", "bbox": [65.2, 76.8, 505.0, 236.7], "size": 32.2}]$$),
    ('baby-talk', 1, $$But Tinu isn’t what Tayo expects. She looks funny. She smells horrible! And even worse…$$, $$[{"role": "BODY", "text": "But Tinu isn’t what Tayo expects. She looks funny.", "bbox": [119.2, 63.5, 447.8, 183.7], "size": 30.0}, {"role": "BODY", "text": "She smells horrible!", "bbox": [933.2, 141.1, 1081.7, 211.4], "size": 31.5}, {"role": "BODY", "text": "And even worse…", "bbox": [636.5, 395.0, 766.6, 465.2], "size": 31.5}]$$),
    ('baby-talk', 2, $$Neh! Neh! She’s too noisy, Mama! Tinu won’t stop crying.$$, $$[{"role": "SFX", "text": "Neh! Neh!", "bbox": [657.8, 57.8, 1051.1, 139.9], "size": 82.1}, {"role": "BODY", "text": "She’s too noisy, Mama! Tinu won’t stop crying.", "bbox": [666.2, 314.1, 1037.8, 382.5], "size": 31.5}]$$),
    ('baby-talk', 3, $$She’s trying to tell you something, Tayo. What do you think she’s saying? I don’t know, says Tayo.$$, $$[{"role": "BODY", "text": "She’s trying to tell you something, Tayo. What do you think she’s saying?", "bbox": [640.9, 107.0, 1063.2, 219.2], "size": 33.0}, {"role": "BODY", "text": "I don’t know, says Tayo.", "bbox": [620.0, 290.8, 830.4, 359.1], "size": 31.5}]$$),
    ('baby-talk', 4, $$Well, I think she’s just hungry. Mama feeds Tinu. But…$$, $$[{"role": "BODY", "text": "Well, I think she’s just hungry. Mama feeds Tinu. But…", "bbox": [125.0, 64.0, 441.9, 185.9], "size": 31.5}]$$),
    ('baby-talk', 5, $$Eh! Tinu cries again. You’ve fed her, why is she still crying? Because need sometimes, a good… babies$$, $$[{"role": "BODY", "text": "Eh! Tinu cries again.", "bbox": [98.3, 74.8, 465.4, 156.9], "size": 30.0}, {"role": "BODY", "text": "You’ve fed her, why is she still crying?", "bbox": [109.4, 192.3, 460.8, 264.9], "size": 33.0}, {"role": "BODY", "text": "Because need sometimes, a good… babies", "bbox": [629.2, 64.0, 1074.8, 136.6], "size": 33.0}]$$),
    ('baby-talk', 6, $$BUUURP!$$, $$[{"role": "SFX", "text": "BUUURP!", "bbox": [90.8, 227.3, 460.4, 309.4], "size": 82.1}]$$),
    ('baby-talk', 7, $$Friends and family want to meet her, but Tinu has never been around so many people. WAAAAHH! Mama takes Tinu to her room for some quiet time.$$, $$[{"role": "BODY", "text": "Friends and family want to meet her, but Tinu has never been around so many people. WAAAAHH! Mama takes Tinu to her room for some quiet time.", "bbox": [623.6, 70.4, 1075.4, 358.1], "size": 36.5}]$$),
    ('baby-talk', 8, $$As time goes by, Tayo learns what Tinu’s cries mean. And she doesn’t seem so bad after all. They even play together.$$, $$[{"role": "BODY", "text": "As time goes by, Tayo learns what Tinu’s cries mean.", "bbox": [779.8, 54.8, 1083.5, 156.8], "size": 30.0}, {"role": "BODY", "text": "And she doesn’t seem so bad after all. They even play together.", "bbox": [780.0, 198.8, 1083.5, 300.8], "size": 30.0}]$$),
    ('baby-talk', 9, $$No, Tinu. Planes are for flying, not chewing. But sometimes, Tinu cries and Tayo doesn’t know what she wants.$$, $$[{"role": "BODY", "text": "No, Tinu. Planes are for flying, not chewing.", "bbox": [98.2, 65.4, 472.0, 138.0], "size": 33.0}, {"role": "BODY", "text": "But sometimes, Tinu cries and Tayo doesn’t know what she wants.", "bbox": [643.4, 60.5, 1057.4, 162.5], "size": 30.0}]$$),
    ('baby-talk', 10, $$Tinu cries through the day... and through the night. Why won’t she stop crying?$$, $$[{"role": "BODY", "text": "Tinu cries through the day...", "bbox": [94.0, 275.1, 472.9, 305.1], "size": 30.0}, {"role": "BODY", "text": "and through the night.", "bbox": [697.2, 275.1, 1003.5, 305.1], "size": 30.0}, {"role": "BODY", "text": "Why won’t she stop crying?", "bbox": [622.3, 422.6, 859.2, 495.2], "size": 33.0}]$$),
    ('baby-talk', 11, $$Wait, what’s that? Look Mama, Tinu’s got her first tooth!$$, $$[{"role": "BODY", "text": "Wait, what’s that? Look Mama,", "bbox": [161.7, 54.8, 405.3, 125.1], "size": 31.5}, {"role": "BODY", "text": "Tinu’s got her first tooth!", "bbox": [649.5, 65.4, 1054.5, 98.4], "size": 33.0}]$$),
    ('baby-talk', 12, $$$$, $$[]$$),
    ('baby-talk', 13, $$$$, $$[]$$),
    ('babys-first-family-photo', 0, $$Whose bright orange wrapper is this? It is Mama’s.$$, $$[{"role": "BODY", "text": "Whose bright orange wrapper is this? It is Mama’s.", "bbox": [109.7, 164.0, 457.2, 424.7], "size": 54.0}]$$),
    ('babys-first-family-photo', 1, $$Whose blue shirt is this? It is Papa’s.$$, $$[{"role": "BODY", "text": "Whose blue shirt is this? It is Papa’s.", "bbox": [139.6, 190.0, 427.3, 398.8], "size": 54.0}]$$),
    ('babys-first-family-photo', 2, $$Whose yellow head wrap is this? It is Gogo’s.$$, $$[{"role": "BODY", "text": "Whose yellow head wrap is this? It is Gogo’s.", "bbox": [66.5, 190.9, 500.4, 399.7], "size": 54.0}]$$),
    ('babys-first-family-photo', 3, $$Whose pretty red dress is this? It is Big Sister’s.$$, $$[{"role": "BODY", "text": "Whose pretty red dress is this? It is Big Sister’s.", "bbox": [80.3, 190.9, 486.6, 399.7], "size": 54.0}]$$),
    ('babys-first-family-photo', 4, $$Whose green and yellow flowery dress is this? It is mine!$$, $$[{"role": "BODY", "text": "Whose green and yellow flowery dress is this? It is mine!", "bbox": [88.5, 164.0, 478.4, 424.7], "size": 54.0}]$$),
    ('babys-first-family-photo', 5, $$“ I love my orange wrapper.” Mama twirls.$$, $$[{"role": "BODY", "text": "“ I love my orange wrapper.” Mama twirls.", "bbox": [90.0, 190.0, 476.9, 398.8], "size": 54.0}]$$),
    ('babys-first-family-photo', 6, $$“ I love my blue shirt.” Papa bows.$$, $$[{"role": "BODY", "text": "“ I love my blue shirt.” Papa bows.", "bbox": [47.7, 215.9, 519.4, 372.8], "size": 54.0}]$$),
    ('babys-first-family-photo', 7, $$“ I love my yellow head wrap.” Gogo jiggles.$$, $$[{"role": "BODY", "text": "“ I love my yellow head wrap.” Gogo jiggles.", "bbox": [95.0, 190.0, 472.9, 398.8], "size": 54.0}]$$),
    ('babys-first-family-photo', 8, $$“ I love my pretty red dress.” Big Sister jumps up and down.$$, $$[{"role": "BODY", "text": "“ I love my pretty red dress.” Big Sister jumps up and down.", "bbox": [75.2, 164.0, 491.6, 424.7], "size": 56.0}]$$),
    ('babys-first-family-photo', 9, $$“ I love my green flowery dress.” I clap my hands.$$, $$[{"role": "BODY", "text": "“ I love my green flowery dress.” I clap my hands.", "bbox": [77.3, 190.0, 489.5, 398.8], "size": 54.0}]$$),
    ('babys-first-family-photo', 10, $$We are ready. SNAP!$$, $$[{"role": "BODY", "text": "We are ready.", "bbox": [104.5, 54.2, 462.5, 112.2], "size": 58.0}, {"role": "SFX", "text": "SNAP!", "bbox": [798.0, 49.6, 1075.7, 228.5], "size": 109.3}]$$),
