    ('catch-that-cat', 0, $$Hurry. Hurry! Help me catch that cat!$$, $$[{"role": "SFX", "text": "Hurry. Hurry!", "bbox": [691.6, 233.2, 827.8, 332.2], "size": 45.0}, {"role": "BODY", "text": "Help me catch that cat!", "bbox": [694.3, 425.0, 1000.8, 452.0], "size": 27.0}]$$),
    ('catch-that-cat', 1, $$She stole my sock and ran off… snatch her. Grab her. Catch that cat!$$, $$[{"role": "BODY", "text": "She stole my sock and ran off… snatch her. Grab her.", "bbox": [646.1, 99.6, 1054.7, 159.0], "size": 27.0}, {"role": "SFX", "text": "Catch that cat!", "bbox": [706.8, 226.9, 994.0, 266.9], "size": 40.0}]$$),
    ('catch-that-cat', 2, $$Look. Look! There she goes. Come on, climb. She’s in the tree. Catch that cat!$$, $$[{"role": "SFX", "text": "Look. Look!", "bbox": [172.4, 114.3, 394.6, 154.3], "size": 40.0}, {"role": "BODY", "text": "There she goes. Come on, climb.", "bbox": [180.3, 223.9, 386.6, 283.3], "size": 27.0}, {"role": "BODY", "text": "She’s in the tree. Catch that cat!", "bbox": [175.0, 321.1, 392.0, 380.5], "size": 27.0}]$$),
    ('catch-that-cat', 3, $$Eek. She jumped! I just missed her. Quick. Fast. Catch that cat!$$, $$[{"role": "BODY", "text": "Eek. She jumped! I just missed her.", "bbox": [108.0, 425.8, 354.1, 491.8], "size": 30.0}, {"role": "BODY", "text": "Quick. Fast. Catch that cat!", "bbox": [757.3, 59.7, 1044.6, 146.5], "size": 35.0}]$$),
    ('catch-that-cat', 4, $$. ssendoog knahT dep l eh kcos ehT . taofl reh . no emoC ot !tac tog taht ev ’ eW hctac$$, $$[{"role": "BODY", "text": ". ssendoog knahT dep l eh kcos ehT . taofl reh", "bbox": [113.1, 294.0, 204.9, 514.8], "size": 16.9}, {"role": "BODY", "text": ". no emoC", "bbox": [438.9, 277.4, 483.9, 480.4], "size": 23.0}, {"role": "BODY", "text": "ot !tac tog taht ev ’ eW hctac", "bbox": [667.2, 52.6, 726.6, 243.6], "size": 16.7}]$$),
    ('catch-that-cat', 5, $$Watch out, everybody. That is one fast cat! Are we ever going to catch that cat?$$, $$[{"role": "BODY", "text": "Watch out, everybody.", "bbox": [90.3, 203.7, 238.0, 263.1], "size": 27.0}, {"role": "BODY", "text": "That is one fast cat!", "bbox": [33.5, 300.9, 294.8, 327.9], "size": 27.0}, {"role": "BODY", "text": "Are we ever going to catch that cat?", "bbox": [757.6, 59.9, 1028.2, 119.3], "size": 27.0}]$$),
    ('catch-that-cat', 6, $$Did you see her jump on a duck? Look at them float. I hope my sock stays dry!$$, $$[{"role": "BODY", "text": "Did you see her jump on a duck? Look at them float.", "bbox": [136.3, 61.4, 389.5, 153.2], "size": 27.0}, {"role": "BODY", "text": "I hope my sock stays dry!", "bbox": [70.7, 209.9, 439.6, 239.9], "size": 30.0}]$$),
    ('catch-that-cat', 7, $$Clever cat. We’ll catch you yet! Hmm. But how?$$, $$[{"role": "BODY", "text": "Clever cat. We’ll catch you yet!", "bbox": [722.5, 164.8, 978.3, 224.2], "size": 27.0}, {"role": "SFX", "text": "Hmm. But how?", "bbox": [761.7, 284.4, 939.1, 372.4], "size": 40.0}]$$),
    ('catch-that-cat', 8, $$Shhh. Quiet. Let’s hide here. Here’s our chance to catch that cat!$$, $$[{"role": "SFX", "text": "Shhh. Quiet.", "bbox": [162.2, 144.0, 390.6, 184.0], "size": 40.0}, {"role": "BODY", "text": "Let’s hide here. Here’s our chance to catch that cat!", "bbox": [777.5, 321.1, 1048.0, 417.2], "size": 28.5}]$$),
    ('catch-that-cat', 9, $$Gotcha!$$, $$[{"role": "SFX", "text": "Gotcha!", "bbox": [60.0, 250.0, 507.0, 370.0], "size": 120.0}]$$),
    ('catch-that-cat', 10, $$Wow! Look here. The sock is for her babies. What sweet kittens!$$, $$[{"role": "SFX", "text": "Wow!", "bbox": [809.8, 167.5, 939.2, 217.5], "size": 50.0}, {"role": "BODY", "text": "Look here.", "bbox": [805.8, 267.0, 943.1, 294.0], "size": 27.0}, {"role": "BODY", "text": "The sock is for her babies. What sweet kittens!", "bbox": [704.0, 331.8, 1045.0, 391.2], "size": 27.0}]$$),
    ('catch-that-cat', 11, $$Quick. Catch all those cats! We’ll bring them home. They can have all my socks.$$, $$[{"role": "BODY", "text": "Quick. Catch all those cats!", "bbox": [718.2, 94.9, 982.6, 154.3], "size": 27.0}, {"role": "BODY", "text": "We’ll bring them home. They can have all my socks.", "bbox": [668.5, 192.1, 1032.2, 251.5], "size": 27.0}]$$),
    ('catch-that-cat', 12, $$$$, $$[]$$),
    ('catch-that-cat', 13, $$$$, $$[]$$),
    ('circles', 0, $$On a cliff there lived a young vulture with his mother.$$, $$[{"role": "BODY", "text": "On a cliff there lived a young vulture with his mother.", "bbox": [623.6, 62.6, 1052.3, 114.6], "size": 22.0}]$$),
    ('circles', 1, $$When he was old enough to fly, his mother took him high into the air and they circled together, watching the ground below. “I want to show you something beautiful,” she told her son. They saw an old gemsbok staggering through the heat. “Look there. That gemsbok won’t last long.”$$, $$[{"role": "BODY", "text": "When he was old enough to fly, his mother took him high into the air and they circled together, watching the ground below.", "bbox": [56.7, 62.6, 499.1, 144.6], "size": 22.0}, {"role": "BODY", "text": "“I want to show you something beautiful,” she told her son.", "bbox": [56.7, 182.6, 489.6, 234.6], "size": 22.0}, {"role": "BODY", "text": "They saw an old gemsbok staggering through the heat. “Look there. That gemsbok won’t last long.”", "bbox": [820.9, 62.6, 1067.0, 204.6], "size": 22.0}]$$),
    ('circles', 2, $$Sure enough, the buck collapsed right there and died. The two vultures flew down. “This isn’t beautiful,” said the young vulture to his mother. “This is horrible!”$$, $$[{"role": "BODY", "text": "Sure enough, the buck collapsed right there and died.", "bbox": [56.7, 361.6, 393.7, 413.6], "size": 22.0}, {"role": "BODY", "text": "The two vultures flew down. “This isn’t beautiful,” said the young vulture to his mother. “This is horrible!”", "bbox": [623.6, 173.3, 1031.2, 255.3], "size": 22.0}]$$),
    ('circles', 3, $$“I know,” said his mother. “Death is very difficult, and very sad. But it is also beautiful.” “No ways,” said the young vulture. “Yuck.” “Just wait,” she said. “We will come back here soon and you will see.”$$, $$[{"role": "BODY", "text": "“I know,” said his mother. “Death is very difficult, and very sad. But it is also beautiful.”", "bbox": [56.7, 62.6, 467.3, 144.6], "size": 22.0}, {"role": "BODY", "text": "“No ways,” said the young vulture. “Yuck.”", "bbox": [56.7, 182.6, 490.0, 204.6], "size": 22.0}, {"role": "BODY", "text": "“Just wait,” she said. “We will come back here soon and you will see.”", "bbox": [623.6, 62.6, 1043.6, 114.6], "size": 22.0}]$$),
    ('circles', 4, $$The next week, they visited the dead buck. Its skeleton was clean and white, and tiny plants had started to grow between the bones.$$, $$[{"role": "BODY", "text": "The next week, they visited the dead buck. Its skeleton was clean and white, and tiny plants had started to grow between the bones.", "bbox": [56.7, 238.3, 497.6, 350.3], "size": 22.0}]$$),
    ('circles', 5, $$The week after that, the shoots had grown tall and blossomed. A butterfly sipped at the flowers and a songololo rested in their shade.$$, $$[{"role": "BODY", "text": "The week after that, the shoots had grown tall and blossomed. A butterfly sipped at the flowers and a songololo rested in their shade.", "bbox": [56.7, 231.2, 448.7, 343.2], "size": 22.0}]$$),
    ('circles', 6, $$A week later, a pair of weavers was picking the leaves to build a nest. Bees were collecting pollen from the blossoms. And a spider had made her home between the buck’s horns.$$, $$[{"role": "BODY", "text": "A week later, a pair of weavers was picking the leaves to build a nest. Bees were collecting pollen from the blossoms. And a spider had made her home between the buck’s horns.", "bbox": [56.7, 249.7, 505.6, 391.6], "size": 22.0}]$$),
    ('circles', 7, $$And the week after that, they saw a young gemsbok nibbling the tasty shoots.$$, $$[{"role": "BODY", "text": "And the week after that, they saw a young gemsbok nibbling the tasty shoots.", "bbox": [56.7, 253.9, 500.0, 305.9], "size": 22.0}]$$),
    ('circles', 8, $$“Well?” said the vulture’s mother. “Look at the life one buck has given. He has given a spider a home and weavers a nest, fed bees and butterflies, sheltered a songololo, and helped the next generation of buck grow strong.” The young vulture smiled.$$, $$[{"role": "BODY", "text": "“Well?” said the vulture’s mother. “Look at the life one buck has given. He has given a spider a home and weavers a nest, fed bees and butterflies, sheltered a songololo, and helped the next generation of buck grow strong.”", "bbox": [56.7, 62.6, 504.5, 234.6], "size": 22.0}, {"role": "BODY", "text": "The young vulture smiled.", "bbox": [56.7, 272.6, 323.8, 294.6], "size": 22.0}]$$),
    ('circles', 9, $$The two of them flew back to their nest high up on the cliff.$$, $$[{"role": "BODY", "text": "The two of them flew back to their nest high up on the cliff.", "bbox": [623.6, 62.6, 1033.9, 114.6], "size": 22.0}]$$),
    ('circles', 10, $$“It is not just our bodies we leave behind when we die,” said the mother vulture. “We also leave our lessons and our love and our memories.”$$, $$[{"role": "BODY", "text": "“It is not just our bodies we leave behind when we die,” said the mother vulture. “We also leave our lessons and our love and our memories.”", "bbox": [623.6, 62.6, 1075.2, 174.6], "size": 22.0}]$$),
    ('circles', 11, $$“Where do we leave all those things?” asked the little vulture. “We leave them in our children and in our family and friends. You are already my green patch on earth, Little Vulture. And you will be, forever.”$$, $$[{"role": "BODY", "text": "“Where do we leave all those things?” asked the little vulture.", "bbox": [302.1, 62.6, 508.6, 174.6], "size": 22.0}, {"role": "BODY", "text": "“We leave them in our children and in our family and friends. You are already my green patch on earth, Little Vulture. And you will be, forever.”", "bbox": [623.6, 62.6, 1052.3, 174.6], "size": 22.0}]$$),
    ('circles', 12, $$$$, $$[]$$),
    ('circles', 13, $$$$, $$[]$$),
    ('clever-pig', 0, $$Come Pig! Let’s play. Can you find the carrot?$$, $$[{"role": "BODY", "text": "Come Pig! Let’s play.", "bbox": [778.8, 144.1, 922.0, 221.1], "size": 35.0}, {"role": "BODY", "text": "Can you find the carrot?", "bbox": [684.6, 396.1, 1016.1, 431.1], "size": 35.0}]$$),
    ('clever-pig', 1, $$No, it’s not under there. No, it’s not inside.$$, $$[{"role": "BODY", "text": "No, it’s not under there.", "bbox": [124.7, 184.7, 442.2, 219.7], "size": 35.0}, {"role": "BODY", "text": "No, it’s not inside.", "bbox": [730.7, 449.0, 970.1, 484.0], "size": 35.0}]$$),
    ('clever-pig', 2, $$Clever Pig!$$, $$[{"role": "BODY", "text": "Clever Pig!", "bbox": [776.8, 273.2, 922.6, 308.2], "size": 35.0}]$$),
    ('clever-pig', 3, $$Wake up, Pig! Come out and play. Where is she?$$, $$[{"role": "BODY", "text": "Wake up, Pig! Come out and play.", "bbox": [148.5, 165.1, 418.4, 242.1], "size": 35.0}, {"role": "BODY", "text": "Where is she?", "bbox": [190.3, 375.1, 376.6, 410.1], "size": 35.0}]$$),
    ('clever-pig', 4, $$Pig is gone.$$, $$[{"role": "BODY", "text": "Pig is gone.", "bbox": [772.8, 270.1, 928.0, 305.1], "size": 35.0}]$$),
    ('clever-pig', 5, $$The sun came up. And the sun went down. But, no Pig.$$, $$[{"role": "BODY", "text": "The sun came up.", "bbox": [221.1, 95.4, 459.9, 130.4], "size": 35.0}, {"role": "BODY", "text": "And the sun went down. But, no Pig.", "bbox": [623.6, 98.4, 1038.2, 175.4], "size": 35.0}]$$),
    ('clever-pig', 6, $$I miss my friend.$$, $$[{"role": "BODY", "text": "I miss my friend.", "bbox": [271.8, 147.5, 490.8, 182.5], "size": 35.0}]$$),
    ('clever-pig', 7, $$My Pig! Clever Pig.$$, $$[{"role": "BODY", "text": "My Pig! Clever Pig.", "bbox": [778.2, 249.1, 922.5, 326.1], "size": 35.0}]$$),
    ('clever-pig', 8, $$And one, two, three new friends!$$, $$[{"role": "BODY", "text": "And one,", "bbox": [56.7, 117.4, 181.1, 152.4], "size": 35.0}, {"role": "BODY", "text": "two,", "bbox": [331.8, 159.4, 389.3, 194.4], "size": 35.0}, {"role": "BODY", "text": "three new friends!", "bbox": [623.6, 223.7, 862.2, 258.7], "size": 35.0}]$$),
    ('clever-pig', 9, $$Come, pigs! Let’s play.$$, $$[{"role": "BODY", "text": "Come, pigs!", "bbox": [107.3, 141.8, 269.7, 176.8], "size": 35.0}, {"role": "BODY", "text": "Let’s play.", "bbox": [782.5, 446.2, 918.3, 481.2], "size": 35.0}]$$),
    ('clever-pig', 10, $$Time for bed!$$, $$[{"role": "BODY", "text": "Time for bed!", "bbox": [760.0, 124.1, 940.8, 159.1], "size": 35.0}]$$),
    ('clever-pig', 11, $$Goodnight, pigs.$$, $$[{"role": "BODY", "text": "Goodnight, pigs.", "bbox": [268.1, 220.8, 491.6, 255.8], "size": 35.0}]$$),
