    ('come-stay-with-me', 0, $$Tendai Turtle lives in the water. Tendai’s best friend is Bunny Busi. She lives in a tree.$$, $$[{"role": "BODY", "text": "Tendai Turtle lives in the water.", "bbox": [76.2, 94.3, 490.8, 124.3], "size": 30.0}, {"role": "BODY", "text": "Tendai’s best friend is Bunny Busi. She lives in a tree.", "bbox": [629.4, 431.6, 1071.4, 497.6], "size": 30.0}]$$),
    ('come-stay-with-me', 1, $$Granny Turtle has hurt her shell.$$, $$[{"role": "BODY", "text": "Granny Turtle has hurt her shell.", "bbox": [745.2, 94.7, 1035.0, 160.7], "size": 30.0}]$$),
    ('come-stay-with-me', 2, $$“We have to go to help Granny,” says Mum. “Come stay with me,” calls Busi.$$, $$[{"role": "BODY", "text": "“We have to go to help Granny,” says Mum.", "bbox": [63.3, 99.0, 503.7, 165.0], "size": 30.0}, {"role": "BODY", "text": "“Come stay with me,” calls Busi.", "bbox": [699.3, 434.4, 1001.5, 500.4], "size": 30.0}]$$),
    ('come-stay-with-me', 3, $$Tendai stays with Bunny Busi in the tree.$$, $$[{"role": "BODY", "text": "Tendai stays with Bunny Busi in the tree.", "bbox": [129.9, 80.5, 437.1, 146.6], "size": 30.0}]$$),
    ('come-stay-with-me', 4, $$They play all day.$$, $$[{"role": "BODY", "text": "They play all day.", "bbox": [169.0, 80.1, 397.9, 110.1], "size": 30.0}]$$),
    ('come-stay-with-me', 5, $$$$, $$[]$$),
    ('come-stay-with-me', 6, $$They sleep all night.$$, $$[{"role": "BODY", "text": "They sleep all night.", "bbox": [132.2, 269.3, 393.7, 299.3], "size": 30.0}]$$),
    ('come-stay-with-me', 7, $$Mum and Dad come back with Granny.$$, $$[{"role": "BODY", "text": "Mum and Dad come back with Granny.", "bbox": [727.7, 145.0, 973.1, 211.0], "size": 30.0}]$$),
    ('come-stay-with-me', 8, $$“How are you, Granny?” asks Tendai.$$, $$[{"role": "BODY", "text": "“How are you, Granny?” asks Tendai.", "bbox": [117.1, 77.0, 449.8, 143.0], "size": 30.0}]$$),
    ('come-stay-with-me', 9, $$“I am better now,” says Granny with a smile. “We fixed her shell,” answers Mum.$$, $$[{"role": "BODY", "text": "“I am better now,” says Granny with a smile.", "bbox": [118.2, 67.8, 448.8, 133.8], "size": 30.0}, {"role": "BODY", "text": "“We fixed her shell,” answers Mum.", "bbox": [703.6, 77.0, 997.2, 143.0], "size": 30.0}]$$),
    ('come-stay-with-me', 10, $$Granny gives Tendai her favourite flute.$$, $$[{"role": "BODY", "text": "Granny gives Tendai her favourite flute.", "bbox": [696.4, 77.0, 1004.4, 143.0], "size": 30.0}]$$),
    ('come-stay-with-me', 11, $$Tendai plays the flute and everybody dances.$$, $$[{"role": "BODY", "text": "Tendai plays the flute and everybody dances.", "bbox": [117.3, 77.0, 449.6, 143.0], "size": 30.0}]$$),
    ('come-stay-with-me', 12, $$$$, $$[]$$),
