    ('feathered-friends', 0, $$We are the oakum boys. We do everything together.$$, $$[{"role": "BODY", "text": "We are the oakum boys. We do everything together.", "bbox": [56.7, 267.9, 464.4, 341.9], "size": 32.0}]$$),
    ('feathered-friends', 1, $$Penguins don’t fly, they swim. But we’re too young to swim. So we walk.$$, $$[{"role": "BODY", "text": "Penguins don’t fly, they swim. But we’re too young to swim.", "bbox": [56.7, 370.2, 495.8, 444.2], "size": 32.0}, {"role": "BODY", "text": "So we walk.", "bbox": [56.7, 496.2, 228.7, 528.2], "size": 32.0}]$$),
    ('feathered-friends', 2, $$One day we went for a long walk. We walked and walked. Until we saw something new.$$, $$[{"role": "BODY", "text": "One day we went for a long walk.", "bbox": [56.7, 81.7, 308.4, 155.7], "size": 32.0}, {"role": "BODY", "text": "We walked and walked. Until we saw something new.", "bbox": [650.0, 454.2, 1077.4, 528.2], "size": 32.0}]$$),
    ('feathered-friends', 3, $$$$, $$[]$$),
    ('feathered-friends', 4, $$He’s got something on his head!$$, $$[{"role": "SFX", "text": "He’s got something on his head!", "bbox": [142.4, 81.7, 424.6, 155.7], "size": 32.0}]$$),
    ('feathered-friends', 5, $$$$, $$[]$$),
    ('feathered-friends', 6, $$You’re changing! So are you!$$, $$[{"role": "SFX", "text": "You’re changing!", "bbox": [158.3, 496.2, 408.7, 528.2], "size": 32.0}, {"role": "SFX", "text": "So are you!", "bbox": [766.8, 496.2, 934.1, 528.2], "size": 32.0}]$$),
    ('feathered-friends', 7, $$$$, $$[]$$),
    ('feathered-friends', 8, $$It’s not so bad! It’s not so cold!$$, $$[{"role": "SFX", "text": "It’s not so bad!", "bbox": [170.2, 496.2, 396.8, 528.2], "size": 32.0}, {"role": "SFX", "text": "It’s not so cold!", "bbox": [733.9, 496.2, 967.0, 528.2], "size": 32.0}]$$),
    ('feathered-friends', 9, $$But who’s going to teach us to swim? I will!$$, $$[{"role": "SFX", "text": "But who’s going to teach us to swim?", "bbox": [147.2, 454.2, 419.9, 528.2], "size": 32.0}, {"role": "SFX", "text": "I will!", "bbox": [807.2, 81.7, 893.7, 113.7], "size": 32.0}]$$),
    ('feathered-friends', 10, $$$$, $$[]$$),
    ('feathered-friends', 11, $$$$, $$[]$$),
    ('feathered-friends', 12, $$$$, $$[]$$),
    ('feathered-friends', 13, $$In this book you’ll meet king penguins, chinstrap penguins, and one lonely macaroni ... as seen through the eyes of the oakum boys, which are what king penguin babies are before they grow up. All of these penguin species (and a few more) are found in Antarctica, the coldest, driest, windiest place on earth. It takes some very special qualities to survive in this harsh landscape. But if you are lucky enough to visit here, you will find that no matter how alike the penguins seem, each one is different – and all of them are special. We hope that by learning about these amazing animals, future generations will want to protect them as much as we do.$$, $$[{"role": "BODY", "text": "In this book you’ll meet king penguins, chinstrap penguins, and one lonely macaroni ... as seen through the eyes of the oakum boys, which are what king penguin babies are before they grow up.", "bbox": [139.1, 112.8, 428.0, 166.8], "size": 12.0}, {"role": "BODY", "text": "All of these penguin species (and a few more) are found in Antarctica, the coldest, driest, windiest place on earth. It takes some very special qualities to survive in this harsh landscape. But if you are lucky enough to visit here, you will find that no matter how alike the penguins seem, each one is different – and all of them are special.", "bbox": [135.5, 182.8, 431.6, 278.8], "size": 12.0}, {"role": "BODY", "text": "We hope that by learning about these amazing animals, future generations will want to protect them as much as we do.", "bbox": [150.7, 294.8, 416.4, 334.8], "size": 12.0}]$$),
    ('fifi-and-teddy', 0, $$Fifi has loved Teddy since she was a baby.$$, $$[{"role": "BODY", "text": "Fifi has loved Teddy since she was a baby.", "bbox": [245.2, 242.8, 450.2, 346.9], "size": 28.0}]$$),
    ('fifi-and-teddy', 1, $$Fifi eats with Teddy. Fifi plays with Teddy.$$, $$[{"role": "BODY", "text": "Fifi eats with Teddy. Fifi plays with Teddy.", "bbox": [150.1, 101.5, 416.8, 167.5], "size": 28.0}]$$),
    ('fifi-and-teddy', 2, $$Fifi takes Teddy wherever she goes. And they curl up together every night.$$, $$[{"role": "BODY", "text": "Fifi takes Teddy wherever she goes.", "bbox": [118.6, 64.6, 448.3, 130.6], "size": 28.0}, {"role": "BODY", "text": "And they curl up together every night.", "bbox": [685.2, 64.6, 1015.6, 130.6], "size": 28.0}]$$),
    ('fifi-and-teddy', 3, $$Fifi knows she cannot take Teddy to school. So every morning she leaves Teddy on her bed.$$, $$[{"role": "BODY", "text": "Fifi knows she cannot take Teddy to school. So every morning she leaves Teddy on her bed.", "bbox": [97.3, 218.7, 469.6, 360.6], "size": 28.0}]$$),
    ('fifi-and-teddy', 4, $$One day, when she comes back from school, Teddy is not there!$$, $$[{"role": "BODY", "text": "One day, when she comes back from school, Teddy is not there!", "bbox": [78.4, 256.6, 488.5, 322.6], "size": 28.0}]$$),
    ('fifi-and-teddy', 5, $$$$, $$[]$$),
