    ('fifi-and-teddy', 7, $$“What’s wrong, Fifi?” asks Mom.$$, $$[{"role": "BODY", "text": "“What’s wrong, Fifi?” asks Mom.", "bbox": [152.8, 257.7, 414.2, 323.7], "size": 28.0}]$$),
