    ('how-do-you-eat', 1, $$How do you eat, flamingo? I eat upside down! I trap shrimp in my beak.$$, $$[{"role": "BODY", "text": "How do you eat, flamingo?", "bbox": [104.9, 110.0, 352.5, 200.0], "size": 43.0}, {"role": "BODY", "text": "I eat upside down! I trap shrimp in my beak.", "bbox": [623.6, 429.9, 1029.2, 520.0], "size": 43.0}]$$),
    ('how-do-you-eat', 2, $$How do you eat, dung beetle? I roll dung into a ball. I chew the wet bits and my babies munch the grass.$$, $$[{"role": "BODY", "text": "How do you eat, dung beetle?", "bbox": [130.4, 339.6, 378.0, 429.6], "size": 43.0}, {"role": "BODY", "text": "I roll dung into a ball. I chew the wet bits and my babies munch the grass.", "bbox": [694.5, 131.1, 1015.0, 315.1], "size": 43.0}]$$),
    ('how-do-you-eat', 3, $$How do you eat, pangolin? I lick up ants with my long, sticky tongue.$$, $$[{"role": "BODY", "text": "How do you eat, pangolin?", "bbox": [130.4, 339.6, 378.0, 429.6], "size": 43.0}, {"role": "BODY", "text": "I lick up ants with my long, sticky tongue.", "bbox": [623.6, 372.1, 1076.6, 462.1], "size": 43.0}]$$),
