    ('i-dont-want-to-go-to-sleep', 0, $$“Goodnight, Nandi.” “Idon’twantto go to sleep!”$$, $$[{"role": "BODY", "text": "“Goodnight, Nandi.”", "bbox": [292.9, 243.9, 481.3, 267.9], "size": 24.0}, {"role": "BODY", "text": "“Idon’twantto go to sleep!”", "bbox": [795.1, 127.5, 1071.0, 205.4], "size": 26.0}]$$),
    ('i-dont-want-to-go-to-sleep', 1, $$“That’s enough now. Goodnight, Nandi.” “I … don’t … want … to … go … to … sleep.”$$, $$[{"role": "BODY", "text": "“That’s enough now. Goodnight, Nandi.”", "bbox": [312.8, 298.8, 502.1, 351.6], "size": 24.0}, {"role": "BODY", "text": "“I … don’t … want … to … go … to … sleep.”", "bbox": [649.0, 112.0, 1065.9, 201.2], "size": 25.8}]$$),
    ('i-dont-want-to-go-to-sleep', 2, $$“Iwantmoresupper. Anotherbook! Justonemoresong?” “Goodnight, Nandi.” “Idon’twanttogotosleep!”$$, $$[{"role": "BODY", "text": "“Iwantmoresupper. Anotherbook! Justonemoresong?”", "bbox": [286.9, 83.1, 507.2, 287.8], "size": 28.8}, {"role": "BODY", "text": "“Goodnight, Nandi.”", "bbox": [160.2, 320.4, 348.6, 344.4], "size": 24.0}, {"role": "SFX", "text": "“Idon’twanttogotosleep!”", "bbox": [656.4, 30.7, 1037.5, 141.6], "size": 42.5}]$$),
    ('i-dont-want-to-go-to-sleep', 3, $$“MAMA!ed ... I Please? ne Please.” a glass ofwater. “It’s time to go to sleep now. Goodnight, Nandi.” “I DON’T TO GO WANT TO SLEEP!”$$, $$[{"role": "BODY", "text": "“MAMA!ed ... I Please? ne Please.” a glass ofwater.", "bbox": [126.2, 71.7, 483.5, 249.8], "size": 30.3}, {"role": "BODY", "text": "“It’s time to go to sleep now. Goodnight, Nandi.”", "bbox": [235.3, 400.7, 496.1, 453.5], "size": 24.0}, {"role": "SFX", "text": "“I DON’T TO GO WANT TO SLEEP!”", "bbox": [614.3, 137.0, 875.2, 342.0], "size": 39.5}]$$),
    ('i-dont-want-to-go-to-sleep', 4, $$Mama sighs: “What about an adventure? Do you want an adventure?” “… yes…”$$, $$[{"role": "BODY", "text": "Mama sighs: “What about an adventure? Do you want an adventure?”", "bbox": [96.7, 252.9, 470.3, 305.7], "size": 24.0}, {"role": "BODY", "text": "“… yes…”", "bbox": [934.4, 176.4, 1030.2, 217.9], "size": 27.0}]$$),
    ('i-dont-want-to-go-to-sleep', 5, $$“Do you want to creep through the jungle on the trail of the fearsome hippocrocoturtleduck?” “Yes! Yes! Yes!”$$, $$[{"role": "BODY", "text": "“Do you want to creep through the jungle on the trail of the fearsome hippocrocoturtleduck?”", "bbox": [623.6, 86.9, 846.0, 197.3], "size": 24.0}, {"role": "SFX", "text": "“Yes! Yes! Yes!”", "bbox": [618.9, 268.5, 870.2, 344.0], "size": 38.1}]$$),
