    ('i-dont-want-to-go-to-sleep', 9, $$“Look here, Nandi. Here is your very own adventure boat. It’s waiting to take you wherever you want to go. See, put your head here ... that’s right ... and I’ll just tuck you in ... there we go ... now, off you go! Adventure awaits ...”$$, $$[{"role": "BODY", "text": "“Look here, Nandi.", "bbox": [85.0, 115.2, 261.4, 139.2], "size": 24.0}, {"role": "BODY", "text": "Here is your very own adventure boat.", "bbox": [85.0, 172.8, 441.3, 196.8], "size": 24.0}, {"role": "BODY", "text": "It’s waiting to take you wherever you want to go.", "bbox": [85.0, 230.4, 479.6, 283.2], "size": 24.0}, {"role": "BODY", "text": "See, put your head here ... that’s right ... and I’ll just tuck you in ... there we go ... now, off you go!", "bbox": [85.0, 316.8, 450.1, 398.4], "size": 24.0}, {"role": "BODY", "text": "Adventure awaits ...”", "bbox": [85.0, 432.0, 272.5, 456.0], "size": 24.0}]$$),
